break i continue
break — natychmiast wychodzi z najbliższej otaczającej pętli (lub switch):
for (int i = 1; i &lt; 100; ++i) {
    if (i == 5) break;
    printf("%d ", i);
}
/* Wynik: 1 2 3 4 */
continue — przeskakuje resztę bieżącej iteracji i wraca do warunku:
for (int i = 1; i &lt;= 10; ++i) {
    if (i % 3 == 0) continue;  /* pomiń wielokrotności 3 */
    printf("%d ", i);
}
/* Wynik: 1 2 4 5 7 8 10 */


Pętle nieskończone
Wszystkie poniższe zapisy tworzą pętlę nieskończoną:
while (1) { ... }
for (;;) { ... }
do { ... } while (1);
Przerywa się je za pomocą break, return lub wywołania exit().
/* Typowy wzorzec — pętla główna programu */
for (;;) {
    printf("Podaj komendę (q = wyjście): ");
    char cmd;
    scanf(" %c", &cmd);
    if (cmd == 'q') break;
    /* ... obsługa komendy ... */
}


Instrukcja goto
goto pozwala na bezwarunkowy skok do etykiety:
    goto koniec;
    printf("To się nigdy nie wykona\n");
koniec:
    printf("Skok!\n");






CautionUnikaj goto



Użycie goto sprawia, że kod staje się trudny do śledzenia i debugowania (“spaghetti code”). W niemal każdym przypadku lepiej użyć pętli, break lub return. Jedynym powszechnie akceptowanym wyjątkiem jest wyjście z zagnieżdżonych pętli lub obsługa błędów w C (cleanup pattern):
int przetwarzaj(void)
{
    FILE *f = fopen("dane.txt", "r");
    if (!f) goto blad;

    int *buf = malloc(1024);
    if (!buf) goto zamknij_plik;

    /* ... normalna praca ... */
    free(buf);
    fclose(f);
    return 0;

zamknij_plik:
    fclose(f);
blad:
    return -1;
}




Natychmiastowe zakończenie programu — exit()
Funkcja exit() z &lt;stdlib.h&gt; kończy program natychmiast, z dowolnego miejsca:
#include &lt;stdlib.h&gt;

if (blad_krytyczny) {
    fprintf(stderr, "Błąd krytyczny!\n");
    exit(EXIT_FAILURE);  /* EXIT_FAILURE = 1, EXIT_SUCCESS = 0 */
}

Kompletny przykład: Mini-kalkulator
Łączymy wszystko, czego się dotąd nauczyliśmy:
#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;

int main(void)
{
    double a, b;
    char op;

    printf("=== Mini-kalkulator ===\n");

    for (;;) {
        printf("\nWpisz działanie (np. 12.5 + 3) lub 'q' by wyjść: ");

        /* Sprawdzamy, czy użytkownik wpisał 'q' */
        char buf;
        if (scanf(" %c", &buf) == 1 && buf == 'q') {
            break;
        }
        /* Cofamy przeczytany znak i parsujemy wyrażenie */
        ungetc(buf, stdin);

        if (scanf("%lf %c %lf", &a, &op, &b) != 3) {
            printf("Błędny format!\n");
            while (getchar() != '\n');  /* czyścimy bufor */
            continue;
        }

        switch (op) {
            case '+': printf("= %g\n", a + b); break;
            case '-': printf("= %g\n", a - b); break;
            case '*': printf("= %g\n", a * b); break;
            case '/':
                if (b == 0) {
                    printf("Błąd: dzielenie przez zero!\n");
                } else {
                    printf("= %g\n", a / b);
                }
                break;
            case '%':
                if ((int)b == 0) {
                    printf("Błąd: modulo przez zero!\n");
                } else {
                    printf("= %d\n", (int)a % (int)b);
                }
                break;
            default:
                printf("Nieznany operator: '%c'\n", op);
                break;
        }
    }

    printf("Do widzenia!\n");
    return 0;
}

Tworzenie funkcji
Funkcja składa się z czterech elementów:

Typ zwracany — jaki rodzaj wartości funkcja oddaje wywołującemu.
Nazwa — identyfikator, którym wywołujemy funkcję.
Lista parametrów — dane wejściowe (mogą być puste).
Ciało — blok instrukcji w nawiasach { }.

typ_zwracany nazwa(typ1 param1, typ2 param2, ...)
{
    /* ciało funkcji */
    return wartość;
}
Przykład — funkcja obliczająca pole prostokąta:
double pole_prostokata(double szerokosc, double wysokosc)
{
    return szerokosc * wysokosc;
}

Procedury — funkcje bez wartości zwracanej
Jeśli funkcja nie zwraca wartości, jej typ zwracany to void:
void powitaj(const char *imie)
{
    printf("Witaj, %s!\n", imie);
    /* brak return lub: return; (bez wartości) */
}


Wywoływanie funkcji
#include &lt;stdio.h&gt;

double pole_prostokata(double szer, double wys)
{
    return szer * wys;
}

void wypisz_pole(double szer, double wys)
{
    printf("Pole: %.2f\n", pole_prostokata(szer, wys));
}

int main(void)
{
    double s = 5.0, w = 3.0;
    double p = pole_prostokata(s, w);   /* wywołanie z przypisaniem wyniku */
    printf("Pole = %.2f\n", p);         /* Pole = 15.00 */

    wypisz_pole(7.0, 2.5);             /* Pole: 17.50 */
    return 0;
}

Deklarowanie funkcji (prototypy)
Kompilator C czyta kod od góry do dołu. Jeśli wywołamy funkcję przed jej definicją, kompilator nie będzie jej znał:
int main(void)
{
    printf("%d\n", kwadrat(5));  /* BŁĄD: kompilator nie zna 'kwadrat' */
    return 0;
}

int kwadrat(int x)
{
    return x * x;
}
Rozwiązanie — prototyp (deklaracja) funkcji umieszczony przed main:
/* Prototyp — informuje kompilator o sygnaturze funkcji */
int kwadrat(int x);

int main(void)
{
    printf("%d\n", kwadrat(5));  /* OK — kompilator zna sygnaturę */
    return 0;
}

/* Definicja — pełna implementacja */
int kwadrat(int x)
{
    return x * x;
}
W prototypie nazwy parametrów są opcjonalne — wystarczą same typy: int kwadrat(int);. Jednak podanie nazw poprawia czytelność.






TipPliki nagłówkowe



W dużych projektach prototypy umieszcza się w plikach nagłówkowych (.h), a definicje w plikach źródłowych (.c):
/* matematyka.h */
#ifndef MATEMATYKA_H
#define MATEMATYKA_H
double pole_prostokata(double szer, double wys);
double pole_kola(double r);
#endif
/* matematyka.c */
#include "matematyka.h"
#include &lt;math.h&gt;

double pole_prostokata(double szer, double wys) { return szer * wys; }
double pole_kola(double r) { return M_PI * r * r; }

Przekazywanie argumentów

Przekazywanie przez wartość (by value)
W C argumenty są zawsze przekazywane przez wartość — funkcja otrzymuje kopię danych. Modyfikacja parametru wewnątrz funkcji nie wpływa na zmienną w kodzie wywołującym:
void podwoj(int x)
{
    x = x * 2;
    printf("Wewnątrz: %d\n", x);  /* 10 */
}

int main(void)
{
    int a = 5;
    podwoj(a);
    printf("Na zewnątrz: %d\n", a);  /* nadal 5! */
    return 0;
}
Aby funkcja mogła zmodyfikować zmienną wywołującego, trzeba przekazać wskaźnik (adres) — poznamy to w Wykładzie 7.
void podwoj(int *x)    /* przyjmuje wskaźnik (adres) */
{
    *x = *x * 2;       /* modyfikuje wartość pod adresem */
}

int main(void)
{
    int a = 5;
    podwoj(&a);         /* przekazujemy adres zmiennej a */
    printf("%d\n", a);  /* 10 — zmienna została zmodyfikowana */
    return 0;
}


Jak zwrócić kilka wartości?
Funkcja w C może zwrócić tylko jedną wartość przez return. Aby “zwrócić” więcej, stosujemy:

Wskaźniki jako parametry wyjściowe:

void podziel(int a, int b, int *iloraz, int *reszta)
{
    *iloraz = a / b;
    *reszta = a % b;
}

int main(void)
{
    int q, r;
    podziel(17, 5, &q, &r);
    printf("17 / 5 = %d reszta %d\n", q, r);  /* 3 reszta 2 */
    return 0;
}

Struktury (poznamy je w dalszej części kursu):

typedef struct {
    int iloraz;
    int reszta;
} WynikDzielenia;

WynikDzielenia podziel(int a, int b)
{
    WynikDzielenia w;
    w.iloraz = a / b;
    w.reszta = a % b;
    return w;
}

Funkcja main() — szczegóły
main() to punkt wejścia programu. Może przyjmować argumenty linii poleceń:
int main(int argc, char *argv[])
{
    printf("Program: %s\n", argv[0]);
    printf("Liczba argumentów: %d\n", argc);

    for (int i = 1; i &lt; argc; ++i) {
        printf("argv[%d] = %s\n", i, argv[i]);
    }
    return 0;
}
Kompilacja i uruchomienie:
gcc -o test test.c
./test alfa beta 42
Program: ./test
Liczba argumentów: 4
argv[1] = alfa
argv[2] = beta
argv[3] = 42
argc to liczba argumentów (łącznie z nazwą programu), a argv to tablica wskaźników na łańcuchy znaków.
